 22→export async function editFilm(
 23→  id: string,
 24→  data: FilmSchema
 25→): Promise<CreateFilmResponse> {
 26→  try {
 27→    // Validate the data
 28→    const validatedData = filmSchema.parse(data);
 29→
 30→    // Convert number fields from string to number if needed
 31→    const processedData = {
 32→      ...validatedData,
 33→      iso: Number(validatedData.iso),
 34→      price: validatedData.price ? Number(validatedData.price) : undefined,
 35→      count: validatedData.count ? Number(validatedData.count) : undefined,
