 38→      calculated_rolls: validatedData.calculated_rolls ? Number(validatedData.calculated_rolls) : undefined,
 39→      bulk_remaining_exposures: validatedData.bulk_remaining_exposures ? Number(validatedData.bulk_remaining_exposures) : undefined,
 40→      spooled_cassettes: validatedData.spooled_cassettes ? Number(validatedData.spooled_cassettes) : undefined,
 41→    };
 42→
 43→    // Update in Supabase (don't include id, created_at, or user_id in update)
 44→    const supabase = await getDataClient();
 45→    const { error } = await supabase
 46→      .from("films")
 47→      .update(processedData)
 48→      .eq("id", id);
 49→
 50→    if (error) {
 51→      throw error;
 52→    }
 53→
 54→    // Fetch the updated film to return
 55→    const { data: updatedFilm } = await supabase
 56→      .from("films")
