 76→    const validatedData = filmSchema.parse(data);
 77→
 78→    // Get current user (supports demo mode)
 79→    const { userId } = await getEffectiveUser();
 80→
 81→    if (!userId) {
 82→      throw new Error("User not authenticated");
 83→    }
 84→
 85→    // Generate a unique ID for the film
 86→    const filmId = uuidv4();
 87→
 88→    // Create film with ID, timestamp, and user_id
 89→    const newFilm: Film = {
 90→      ...validatedData,
 91→      id: filmId,
 92→      created_at: new Date().toISOString(),
 93→      updated_at: new Date().toISOString(),
 94→      user_id: userId,
