 99→      bulk_quantity: validatedData.bulk_quantity ? Number(validatedData.bulk_quantity) : undefined,
100→      calculated_rolls: validatedData.calculated_rolls ? Number(validatedData.calculated_rolls) : undefined,
101→      bulk_remaining_exposures: validatedData.is_bulk_film ?
102→        (validatedData.bulk_remaining_exposures !== undefined ? Number(validatedData.bulk_remaining_exposures) :
103→          // Calculate initial exposures from bulk film length and format
104→          Number(validatedData.calculated_rolls || 0) * getExposuresPerRoll(validatedData.format)) : undefined,
105→      spooled_cassettes: validatedData.is_bulk_film ? (validatedData.spooled_cassettes !== undefined ? Number(validatedData.spooled_cassettes) : 0) : undefined,
106→    };
107→
108→    // Save to Supabase (use getDataClient for demo mode support)
109→    const supabase = await getDataClient();
110→    const { error } = await supabase.from("films").insert([newFilm]);
111→
112→    if (error) {
113→      throw error;
114→    }
115→
116→    return { success: true, film: newFilm };
117→  } catch (error) {
118→    console.error("Error creating film:", error);
119→    return {
120→      success: false,
121→      error: error instanceof Error ? error.message : "Failed to create film",
122→    };
123→  }
