362→export async function reduceFilmCount(
363→  filmId: string,
364→  quantity: number,
365→  usageNote: string,
366→  tripId?: string
367→) {
368→  const supabase = await getDataClient();
369→
370→  const { data: film, error: filmError } = await supabase
371→    .from("films")
372→    .select("count, is_bulk_film, spooled_cassettes, user_id")
373→    .eq("id", filmId)
374→    .single();
375→
376→  if (filmError || !film) {
377→    return { error: "Film not found" };
378→  }
379→
380→  const currentCount = film.count || 0;
381→  const newCount = Math.max(0, currentCount - quantity);
382→
383→  // For bulk films, also update spooled_cassettes count
384→  const updateData = film.is_bulk_film 
385→    ? { count: newCount, spooled_cassettes: Math.max(0, (film.spooled_cassettes || 0) - quantity) }
386→    : { count: newCount };
387→
388→  const { error: updateError } = await supabase
389→    .from("films")
390→    .update(updateData)
391→    .eq("id", filmId);
392→
393→  if (updateError) {
394→    return { error: updateError.message };
395→  }
396→
397→  const { error: usageError } = await supabase.from("film_usage").insert({
398→    film_id: filmId,
399→    quantity,
400→    usage_note: usageNote,
401→    usage_type: 'shoot', // This is for shooting/using spooled cassettes
402→    ...(tripId && { trip_id: tripId }),
403→  });
404→
405→  if (usageError) {
406→    console.error("Usage error:", usageError);
407→    return { error: `Failed to record usage: ${usageError.message}` };
408→  }
409→
410→  revalidatePath("/films");
411→  return { success: true, newCount };
412→}
