414→export async function spoolBulkFilm(
415→  filmId: string,
416→  exposuresToSpool: number,
417→  cassettesCreated: number,
418→  spoolNote: string
419→) {
420→  const supabase = await getDataClient();
421→
422→  const { data: film, error: filmError } = await supabase
423→    .from("films")
424→    .select("bulk_remaining_exposures, spooled_cassettes, is_bulk_film, format")
425→    .eq("id", filmId)
426→    .single();
427→
428→  if (filmError || !film) {
429→    return { error: "Film not found" };
430→  }
431→
432→  if (!film.is_bulk_film) {
433→    return { error: "This is not a bulk film" };
434→  }
435→
436→  const currentRemainingExposures = film.bulk_remaining_exposures || 0;
437→  const currentSpooledCassettes = film.spooled_cassettes || 0;
438→
439→  if (exposuresToSpool > currentRemainingExposures) {
440→    return { error: "Not enough bulk film remaining" };
441→  }
442→
443→  const newRemainingExposures = currentRemainingExposures - exposuresToSpool;
444→  const newSpooledCassettes = currentSpooledCassettes + cassettesCreated;
445→
446→  // Update film with new remaining exposures and cassette count
447→  const { error: updateError } = await supabase
448→    .from("films")
449→    .update({ 
450→      bulk_remaining_exposures: newRemainingExposures,
451→      spooled_cassettes: newSpooledCassettes,
452→      count: newSpooledCassettes // For bulk films, count represents spooled cassettes
453→    })
454→    .eq("id", filmId);
455→
456→  if (updateError) {
457→    return { error: updateError.message };
458→  }
459→
460→  // Record spooling usage
461→  const { error: usageError } = await supabase.from("film_usage").insert({
462→    film_id: filmId,
463→    quantity: cassettesCreated,
464→    usage_note: spoolNote,
465→    usage_type: 'spool',
466→    exposures_used: exposuresToSpool,
467→  });
468→
469→  if (usageError) {
470→    return { error: "Failed to record spooling" };
471→  }
472→
473→  revalidatePath("/films");
474→  return { 
475→    success: true, 
476→    remainingExposures: newRemainingExposures,
477→    spooledCassettes: newSpooledCassettes 
478→  };
479→}
