export async function permanentlyDeleteFilm(id: string): Promise<{
  success: boolean;
  message?: string;
  error?: Error;
}> {
  try {
    const supabase = await getDataClient();

    // Hard delete - actually remove from database
    const { error } = await supabase.from("films").delete().eq("id", id);

    if (error) {
