    const { data: tripGear, error } = await supabase
      .from("trip_gear")
      .insert({
        trip_id: tripId,
        gear_id: gearId,
      })
      .select()
      .single();

    if (error) {
      throw error;
    }

    revalidatePath("/trips");
    revalidatePath("/gear");
