111→    // Calculate total reserved film count and determine status for each trip
112→    const tripsWithCounts = data?.map(trip => {
113→      const tripFilms = trip.trip_films as { quantity: number }[] | null;
114→      const reserved_film_count = tripFilms?.reduce((total, tf) => total + tf.quantity, 0) || 0;
115→      
116→      // Determine status if not already completed
117→      let status = trip.status;
118→      if (status !== 'completed') {
119→        const startDate = new Date(trip.start_date);
120→        const endDate = new Date(trip.end_date);
121→        const today = new Date();
122→        // Set time to 00:00:00 to compare dates only
123→        startDate.setHours(0, 0, 0, 0);
124→        endDate.setHours(0, 0, 0, 0);
125→        today.setHours(0, 0, 0, 0);
126→        
127→        if (startDate > today) {
128→          status = 'upcoming';
129→        } else if (endDate < today) {
130→          status = 'past';
131→        } else {
132→          status = 'ongoing';
133→        }
134→      }
135→
136→      // Remove trip_films from the final object and add reserved_film_count and status
137→      // eslint-disable-next-line @typescript-eslint/no-unused-vars
138→      const { trip_films, ...tripData } = trip;
139→      return {
140→        ...tripData,
141→        reserved_film_count,
142→        status,
143→      };
144→    }) || [];
145→
146→    return { data: tripsWithCounts, error: null };
