export async function getFilmWithDetails(id: string): Promise<{
  film: Film | null;
  usage: FilmUsage[] | null;
  trips: TripFilmReservation[] | null;
  error: string | null;
}> {
  try {
    const { userId } = await getEffectiveUser();
    const supabase = await getDataClient();

    // Get the film
    const { data: film, error: filmError } = await supabase
      .from("films")
      .select("*")
      .eq("id", id)
      .eq("user_id", userId)
      .is("deleted_at", null)
      .single();

    if (filmError) {
      throw filmError;
    }

    // Get usage history
    const { data: usage, error: usageError } = await supabase
      .from("film_usage")
      .select("*")
      .eq("film_id", id)
      .order("created_at", { ascending: false });

    if (usageError) {
      console.warn("Error fetching usage history:", usageError);
    }

    // Get trips that this film is reserved for
    const { data: trips, error: tripsError } = await supabase
      .from("trip_films")
      .select(`
        quantity,
        created_at,
        trips!inner(
          id,
          title,
          description,
          start_date,
          end_date,
          status
        )
      `)
      .eq("film_id", id);

    if (tripsError) {
      console.warn("Error fetching trips:", tripsError);
    }

    return {
      film,
      usage: usage || [],
      trips: (trips || []) as unknown as TripFilmReservation[],
      error: null,
    };
  } catch (error) {
    console.error("Error fetching film details:", error);
    return {
      film: null,
      usage: null,
      trips: null,
      error: error instanceof Error ? error.message : "Failed to fetch film details",
    };
  }
}

export async function deleteFilm(id: string): Promise<{
  success: boolean;
  message?: string;
  error?: Error;
}> {
  try {
    const { userId } = await getEffectiveUser();
    const supabase = await getDataClient();

