  id: string,
  data: TripSchema
): Promise<CreateTripResponse> {
  try {
    const validatedData = tripSchema.parse(data);
    const { userId } = await getEffectiveUser();

    const supabase = await getDataClient();
    const { error } = await supabase
      .from("trips")
      .update(validatedData)
      .eq("id", id)
      .eq("user_id", userId);

    if (error) {
