  tripId: string,
  filmId: string,
  quantity: number = 1
): Promise<{
  success: boolean;
  error?: string;
}> {
  try {
    const { userId } = await getEffectiveUser();
    const supabase = await getDataClient();

    // Verify trip belongs to current user
    const { data: trip, error: tripError } = await supabase
      .from("trips")
