      // Create new reservation
      const tripFilm: Omit<TripFilm, "id" | "created_at"> = {
        trip_id: tripId,
        film_id: filmId,
        quantity,
      };

      const { error } = await supabase.from("trip_films").insert([tripFilm]);

      if (error) {
        throw error;
      }
