export async function addFilmToTrip(
  tripId: string,
  filmId: string,
  quantity: number = 1
): Promise<{
  success: boolean;
  error?: string;
}> {
  try {
    const { userId } = await getEffectiveUser();
    const supabase = await getDataClient();

    // Verify trip belongs to current user
    const { data: trip, error: tripError } = await supabase
      .from("trips")
      .select("id")
      .eq("id", tripId)
      .eq("user_id", userId)
      .single();

    if (tripError || !trip) {
      return { success: false, error: "Trip not found" };
    }

    // Check if this film is already in the trip
    const { data: existingTripFilm } = await supabase
      .from("trip_films")
      .select("*")
      .eq("trip_id", tripId)
      .eq("film_id", filmId)
      .single();

    if (existingTripFilm) {
      // Update existing reservation by adding to the quantity
      const newQuantity = existingTripFilm.quantity + quantity;
      const { error } = await supabase
        .from("trip_films")
        .update({ quantity: newQuantity })
        .eq("trip_id", tripId)
        .eq("film_id", filmId);

      if (error) {
        throw error;
      }
    } else {
      // Create new reservation
      const tripFilm: Omit<TripFilm, "id" | "created_at"> = {
        trip_id: tripId,
        film_id: filmId,
        quantity,
      };

      const { error } = await supabase.from("trip_films").insert([tripFilm]);

      if (error) {
        throw error;
      }
    }

    revalidatePath("/trips");
    revalidatePath("/films");
    return { success: true };
  } catch (error) {
    console.error("Error adding film to trip:", error);
