    const supabase = await getDataClient();
    const { error } = await supabase
      .from("trips")
      .update(validatedData)
      .eq("id", id)
      .eq("user_id", userId);

    if (error) {
      throw error;
    }

    const { data: updatedTrip } = await supabase
